mapper.select:
/* SQL ID : QbnkQstnDAO.qbnkQstnList 설 명 : 문제은행문항목록조회 */ SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY QSTN.REG_DTTM ASC) AS LINE_NO , QSTN.* , COUNT(QSTN.QBNK_QSTN_ID) OVER() AS TOTAL_CNT FROM ( SELECT QSTN.QBNK_QSTN_ID , CASE WHEN CTGR.UP_QBNK_CTGR_ID IS NULL THEN CTGR.CTGRNM ELSE (SELECT CTGRNM FROM TB_LMS_QBNK_CTGR WHERE QBNK_CTGR_ID = CTGR.UP_QBNK_CTGR_ID) END UP_QBNK_CTGRNM , CASE WHEN CTGR.UP_QBNK_CTGR_ID IS NULL THEN '-' ELSE CTGR.CTGRNM END AS CTGRNM , SBJCT.SBJCTNM , SBJCT.DVCLAS_NO , USR.USERNM , QSTN.QSTN_TTL , (SELECT CDNM FROM TB_LMS_CMMN_CD WHERE UP_CD = 'QSTN_RSPNS_TYCD' AND CD = QSTN.QSTN_RSPNS_TYCD) AS QSTN_RSPNS_TYNM , (SELECT CDNM FROM TB_LMS_CMMN_CD WHERE UP_CD = 'QSTN_DFCTLV_TYCD' AND CD = QSTN.QSTN_DFCTLV_TYCD) AS QSTN_DFCTLV_TYNM , QSTN.REG_DTTM FROM TB_LMS_QBNK_QSTN QSTN JOIN TB_LMS_QBNK_CTGR CTGR ON CTGR.QBNK_CTGR_ID = QSTN.QBNK_CTGR_ID AND CTGR.DELYN = 'N' LEFT JOIN TB_LMS_SBJCT SBJCT ON CTGR.SBJCT_ID = SBJCT.SBJCT_ID AND SBJCT.DELYN = 'N' AND SBJCT.USEYN = 'Y' LEFT JOIN TB_LMS_SBJCT_ADM SBJCT_ADM ON SBJCT_ADM.SBJCT_ID = SBJCT.SBJCT_ID AND SBJCT_ADM.USER_ID = CTGR.USER_ID AND SBJCT_ADM.SBJCT_ADM_TYCD = 'PROF' AND SBJCT_ADM.SBJCT_ADM_SEQNO = 1 LEFT JOIN TB_LMS_USER USR ON USR.USER_ID = SBJCT_ADM.USER_ID WHERE QSTN.DELYN = 'N'
AND ( CTGR.UP_QBNK_CTGR_ID = #{upQbnkCtgrId} OR CTGR.QBNK_CTGR_ID = #{upQbnkCtgrId} )
AND CTGR.QBNK_CTGR_ID = #{qbnkCtgrId}
AND CTGR.SBJCT_ID = #{sbjctId}
AND CTGR.USER_RPRS_ID = #{userRprsId}
AND LOWER(QSTN.QSTN_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
) QSTN ORDER BY QSTN.REG_DTTM DESC ) A WHERE 1=1
AND LINE_NO BETWEEN #{firstIndex} +1 AND #{firstIndex} + #{listScale}

mapper.insert:
		/*
             SQL ID : QbnkQstnDAO.qbnkQstnRegist
             설  명 : 문제은행문항등록
         */
        INSERT INTO TB_LMS_QBNK_QSTN (
         	  QBNK_QSTN_ID
			, QBNK_CTGR_ID
			, QSTN_SEQNO
			, USER_ID
			, QSTN_TTL
			, QSTN_CTS
			, QSTN_RSPNS_TYCD
			, QSTN_SCR
			, CRANS_TYCD
			, QSTN_DFCTLV_TYCD
			, RGTR_ID
			, REG_DTTM
         ) VALUES (
         	  #{qbnkQstnId}
			, #{qbnkCtgrId}
			, #{qstnSeqno}
			, #{userId}
			, #{qstnTtl}
			, #{qstnCts}
			, #{qstnRspnsTycd}
			, #{qstnScr}
			, #{cransTycd}
			, #{qstnDfctlvTycd}
			, #{rgtrId}
			, FN_DTTM()
         )

mapper.update:
		/*
             SQL ID : QbnkQstnDAO.qbnkQstnModfiy
             설  명 : 문제은행문항수정
         */
        UPDATE TB_LMS_QBNK_QSTN SET
        	  MDFR_ID   = #{mdfrId}
    		, MOD_DTTM = FN_DTTM()
    		, CRANS_TYCD = #{cransTycd}

    		, QSTN_TTL = #{qstnTtl}


    		, QSTN_CTS = #{qstnCts}


    		, QSTN_RSPNS_TYCD = #{qstnRspnsTycd}


    		, QSTN_DFCTLV_TYCD = #{qstnDfctlvTycd}

    	 WHERE QBNK_QSTN_ID = #{qbnkQstnId}

		/*
             SQL ID : QbnkQstnDAO.qbnkQstnDelynModify
             설  명 : 문제은행문항삭제여부수정
         */
        UPDATE TB_LMS_QBNK_QSTN SET
        	  MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()
			, DELYN = 'Y'
		 WHERE QBNK_QSTN_ID = #{qbnkQstnId}
